mapper.select:
select sri2.cur_time as date, sri2.trade_amount as tradeAmt, sri2.stock_code as code, sri2.min_price as lowPrice, sri2.stock_name as name, sri2.max_price as highPrice, sri2.open_price as openPrice, sri2.trade_volume as tradeVol, sri2.cur_price as closePrice, sri2.pre_close_price as preClosePrice from stock_rt_info as sri2 where sri2.stock_code = #{stockCode} and sri2.cur_time in
#{time}
order by sri2.cur_time
